import React, { useEffect, useState } from 'react';
import {
  Bar, BarChart, CartesianGrid, Line, LineChart, ResponsiveContainer, Tooltip, XAxis, YAxis,
} from 'recharts';
import api from '../utils/api';
import Sidebar from '../components/common/Sidebar';

const number = (value, decimals = 0) => {
  const n = parseFloat(value);
  return Number.isFinite(n) ? n.toFixed(decimals) : (0).toFixed(decimals);
};

const grams = (value) => `${number(value, 0)} g`;
const hours = (value) => `${number(value, 1)}h`;

const MetricCard = ({ label, value, color = 'var(--text-primary)', sub }) => (
  <div className="kpi-card">
    <div className="kpi-value" style={{ color }}>{value}</div>
    <div className="kpi-label">{label}</div>
    {sub && <div style={{ fontSize: '0.7rem', color: 'var(--text-muted)', marginTop: '0.25rem' }}>{sub}</div>}
  </div>
);

const CustomTooltip = ({ active, payload, label }) => {
  if (!active || !payload?.length) return null;
  return (
    <div style={{ background: 'var(--bg-card)', border: '1px solid var(--border-light)', borderRadius: 6, padding: '0.6rem 0.85rem', fontSize: '0.8rem' }}>
      <div style={{ color: 'var(--text-muted)', marginBottom: '0.25rem' }}>{label}</div>
      {payload.map((p, i) => (
        <div key={i} style={{ color: p.color || 'var(--accent)' }}>
          {p.name}: <strong>{p.value}</strong>
        </div>
      ))}
    </div>
  );
};

export default function ResourceDashboardPage() {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    setLoading(true);
    setError('');
    api.get('/dashboard/resources')
      .then(r => {
        setData(r.data);
        setLoading(false);
      })
      .catch(err => {
        setError(err.response?.data?.error || 'Failed to load resource dashboard');
        setLoading(false);
      });
  }, []);

  const materialTrend = (data?.materialConsumption?.trend || []).map(row => ({
    month: row.month ? new Date(row.month).toLocaleDateString('fr-FR', { month: 'short', year: '2-digit' }) : '?',
    consumed: parseFloat(row.consumed || 0),
  }));

  const materialByType = data?.materialConsumption?.byMaterial || [];
  const forecast = data?.capacityForecast || {};
  const summary = data?.summary || {};

  return (
    <div className="page">
      <Sidebar />
      <div className="main-content">
        <div className="page-header">
          <div>
            <div style={{ color: 'var(--text-muted)', fontSize: '0.72rem', marginBottom: '0.25rem' }}>
              Dashboards / Resource Dashboard
            </div>
            <h1 style={{ fontSize: '1.3rem', fontFamily: 'var(--font-heading)' }}>Resource Dashboard</h1>
            <p style={{ color: 'var(--text-muted)', fontSize: '0.8rem', marginTop: '0.2rem' }}>
              Production resources, stock risk, and capacity forecast
            </p>
          </div>
        </div>

        <div className="page-body">
          {error && <div className="alert alert-error" style={{ marginBottom: '1rem' }}>{error}</div>}

          {loading ? (
            <div style={{ display: 'flex', justifyContent: 'center', padding: '3rem' }}>
              <span className="spinner" style={{ width: 32, height: 32 }}/>
            </div>
          ) : (
            <>
              <div className="grid-4" style={{ marginBottom: '1.5rem' }}>
                <MetricCard label="Printer Utilization" value={`${number(summary.printerUtilization, 1)}%`} color="var(--blue)" sub="Last 30 days" />
                <MetricCard label="Technician Utilization" value={`${number(summary.technicianUtilization, 1)}%`} color="var(--green)" sub="Last 30 days" />
                <MetricCard label="Low Stock Materials" value={summary.lowStockMaterials || 0} color={(summary.lowStockMaterials || 0) > 0 ? 'var(--yellow)' : 'var(--green)'} />
                <MetricCard label="Forecast Requests" value={summary.forecastRequests || 0} color="var(--accent)" sub="Monthly average" />
              </div>

              <div className="grid-2" style={{ marginBottom: '1.5rem' }}>
                <div className="card">
                  <h3 style={{ fontSize: '0.8rem', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '1rem' }}>Printer Utilization</h3>
                  <div className="table-container">
                    <table>
                      <thead>
                        <tr><th>Printer</th><th>Utilization %</th><th>Print Hours</th><th>Active Jobs</th></tr>
                      </thead>
                      <tbody>
                        {(data?.printerUtilization || []).map(row => (
                          <tr key={row.id}>
                            <td style={{ fontWeight: 600 }}>{row.printer}</td>
                            <td style={{ color: parseFloat(row.utilization || 0) >= 85 ? 'var(--yellow)' : 'var(--green)', fontWeight: 700 }}>{number(row.utilization, 1)}%</td>
                            <td>{hours(row.print_hours)}</td>
                            <td>{parseInt(row.active_jobs || 0, 10)}</td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </div>

                <div className="card">
                  <h3 style={{ fontSize: '0.8rem', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '1rem' }}>Technician Utilization</h3>
                  <div className="table-container">
                    <table>
                      <thead>
                        <tr><th>Technician</th><th>Utilization %</th><th>Assigned Requests</th><th>Print Hours</th></tr>
                      </thead>
                      <tbody>
                        {(data?.technicianUtilization || []).map(row => (
                          <tr key={row.id}>
                            <td style={{ fontWeight: 600 }}>{row.technician}</td>
                            <td style={{ color: parseFloat(row.utilization || 0) >= 85 ? 'var(--yellow)' : 'var(--green)', fontWeight: 700 }}>{number(row.utilization, 1)}%</td>
                            <td>{parseInt(row.assigned_requests || 0, 10)}</td>
                            <td>{hours(row.print_hours)}</td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </div>
              </div>

              <div className="grid-2" style={{ marginBottom: '1.5rem' }}>
                <div className="card">
                  <h3 style={{ fontSize: '0.8rem', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '1rem' }}>Material Consumption</h3>
                  {materialByType.length > 0 ? (
                    <ResponsiveContainer width="100%" height={240}>
                      <BarChart data={materialByType.map(row => ({ name: row.material, consumed: parseFloat(row.consumed || 0) }))} layout="vertical" barSize={16}>
                        <XAxis type="number" tick={{ fill: 'var(--text-muted)', fontSize: 11 }} axisLine={false} tickLine={false}/>
                        <YAxis type="category" dataKey="name" tick={{ fill: 'var(--text-secondary)', fontSize: 11 }} axisLine={false} tickLine={false} width={130}/>
                        <Tooltip content={<CustomTooltip/>}/>
                        <Bar dataKey="consumed" fill="var(--cyan)" name="Material Used (g)" radius={[0,4,4,0]}/>
                      </BarChart>
                    </ResponsiveContainer>
                  ) : <div className="empty-state" style={{ padding: '2rem' }}><p>No material consumption in the last 30 days</p></div>}
                </div>

                <div className="card">
                  <h3 style={{ fontSize: '0.8rem', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '1rem' }}>Consumption Trend</h3>
                  {materialTrend.length > 0 ? (
                    <ResponsiveContainer width="100%" height={240}>
                      <LineChart data={materialTrend}>
                        <CartesianGrid strokeDasharray="3 3" stroke="var(--border)" vertical={false}/>
                        <XAxis dataKey="month" tick={{ fill: 'var(--text-muted)', fontSize: 11 }} axisLine={false} tickLine={false}/>
                        <YAxis tick={{ fill: 'var(--text-muted)', fontSize: 11 }} axisLine={false} tickLine={false} width={44}/>
                        <Tooltip content={<CustomTooltip/>}/>
                        <Line type="monotone" dataKey="consumed" stroke="var(--accent)" strokeWidth={2} name="Material Used (g)" dot={{ r: 4, fill: 'var(--accent)' }}/>
                      </LineChart>
                    </ResponsiveContainer>
                  ) : <div className="empty-state" style={{ padding: '2rem' }}><p>No consumption trend data</p></div>}
                </div>
              </div>

              <div className="grid-2">
                <div className="card">
                  <h3 style={{ fontSize: '0.8rem', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '1rem' }}>Stock Risk</h3>
                  <div className="table-container">
                    <table>
                      <thead>
                        <tr><th>Low Stock Materials</th><th>Remaining Quantity</th><th>Days of Coverage</th></tr>
                      </thead>
                      <tbody>
                        {(data?.stockRisk || []).map(row => (
                          <tr key={row.id}>
                            <td style={{ fontWeight: 600 }}>{row.material}</td>
                            <td>{number(row.remaining_quantity, 0)} {row.unit}</td>
                            <td style={{ color: row.days_of_coverage === null || parseFloat(row.days_of_coverage) <= 7 ? 'var(--red)' : 'var(--yellow)', fontWeight: 700 }}>
                              {row.days_of_coverage === null ? 'No usage history' : `${number(row.days_of_coverage, 1)} days`}
                            </td>
                          </tr>
                        ))}
                        {(data?.stockRisk || []).length === 0 && (
                          <tr><td colSpan="3" style={{ color: 'var(--text-muted)' }}>No materials below minimum threshold</td></tr>
                        )}
                      </tbody>
                    </table>
                  </div>
                </div>

                <div className="card">
                  <h3 style={{ fontSize: '0.8rem', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '1rem' }}>Capacity Forecast</h3>
                  <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
                    <MetricCard label="Available Printer Capacity" value={hours(forecast.availablePrinterCapacity)} color="var(--blue)" />
                    <MetricCard label="Available Technician Capacity" value={hours(forecast.availableTechnicianCapacity)} color="var(--green)" />
                    <MetricCard label="Forecast Resource Demand" value={hours(forecast.forecastResourceDemand)} color="var(--accent)" />
                    <MetricCard label="Forecast Requests" value={forecast.forecastRequests || 0} color="var(--purple)" />
                  </div>
                </div>
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  );
}
